function flashsort(arr) {
	let n = arr.length;
	if (n <= 1) return arr;
	let max = Math.max(...arr);
	let min = Math.min(...arr);
	let range = max - min;
	if (range === 0) return arr;
	let m = Math.floor(0.45 * n);
	let dist = new Array(m).fill(0);
	for (let i = 0; i < n; i++) {
		let bucket = Math.floor((m - 1) * (arr[i] - min) / range);
		dist[bucket]++;
	}
	for (let i = 1; i < m; i++) {
		dist[i] += dist[i - 1];
	}
	let count = 0;
	let j = 0;
	let k = m - 1;
	while (count < n) {
		while (j > dist[k] - 1) {
			j++;
			k = Math.floor((m - 1) * (arr[j] - min) / range);
		}
		let flash = arr[j];
		while (j !== dist[k]) {
			k = Math.floor((m - 1) * (flash - min) / range);
			dist[k]--;
			let temp = arr[dist[k]];
			arr[dist[k]] = flash;
			flash = temp;
			count++;
		}
	}
	for (let i = 1; i < n; i++) {
		let key = arr[i];
		let j = i - 1;
		while (j >= 0 && arr[j] > key) {
			arr[j + 1] = arr[j];
			j--;
		}
		arr[j + 1] = key;
	}
	return arr;
}

